/* 1. THE FOUNDATION (APPLE DARK MODE) */
:root {
  --bg: #000000;
  --panel: rgba(28, 28, 30, 0.7); /* Apple Glassmorphism */
  --accent: #f1f704; /* Your Signature Yellow */
  --text-main: #f5f5f7;
  --text-dim: #86868b;
  --glass-border: rgba(255, 255, 255, 0.1);
}

/* 2. THE BACKGROUND SCANLINES (DEAD SPACE VIBE) */
body::before {
  content: " ";
  display: block;
  position: fixed;
  top: 0; left: 0; bottom: 0; right: 0;
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.1) 50%), 
              linear-gradient(90deg, rgba(255, 0, 0, 0.02), rgba(0, 255, 0, 0.01), rgba(0, 0, 255, 0.02));
  z-index: 9999;
  pointer-events: none;
  background-size: 100% 2px, 3px 100%;
}

/* 3. THE PROFESSIONAL PANELS (APPLE BENTO LOOK) */
.card {
  background: var(--panel) !important;
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid var(--glass-border) !important;
  border-radius: 22px !important; /* Precision Curves */
  padding: 30px !important;
  transition: transform 0.4s cubic-bezier(0.4, 0, 0.2, 1), border-color 0.3s !important;
  box-shadow: 0 10px 30px rgba(0,0,0,0.5);
}

.card:hover {
  transform: scale(1.02);
  border-color: var(--accent) !important;
}

/* 4. TYPOGRAPHY & INTERFACE */
h1, h2, h3 {
  font-family: -apple-system, BlinkMacSystemFont, "Inter", sans-serif;
  font-weight: 600;
  letter-spacing: -0.03em;
  color: var(--text-main);
  text-transform: none; /* Keeps it modern Apple style */
}

.tag {
  background: var(--accent) !important;
  color: #000 !important;
  border-radius: 6px !important;
  padding: 4px 10px !important;
  font-family: 'Courier New', monospace;
  font-size: 11px;
}

/* 5. SMOOTH NAVIGATION GLOW */
nav a {
  transition: 0.3s;
}

nav a:hover {
  color: var(--accent) !important;
  text-shadow: 0 0 10px var(--accent);
}

/* 6. THE CV BUTTON */
.btn-cv {
  background: var(--text-main);
  color: #000;
  padding: 12px 25px;
  border-radius: 25px;
  text-decoration: none;
  font-weight: 600;
  display: inline-block;
  transition: 0.3s;
}

.btn-cv:hover {
  background: var(--accent);
  transform: translateY(-2px);
}
